document.addEventListener("DOMContentLoaded",()=>{let t=document.querySelectorAll(".filter"),e=document.querySelectorAll(".gal-item");0!==t.length&&0!==e.length&&t.forEach(l=>{l.addEventListener("click",()=>{t.forEach(t=>{t.classList.remove("active")}),l.classList.add("active");let s=l.getAttribute("data-filter");e.forEach(t=>{"all"===s?(t.style.display="block",setTimeout(()=>{t.style.opacity="1",t.style.transform="scale(1)"},100)):t.classList.contains(s)?(t.style.display="block",setTimeout(()=>{t.style.opacity="1",t.style.transform="scale(1)"},100)):(t.style.opacity="0",t.style.transform="scale(0.8)",setTimeout(()=>{t.style.display="none"},300))})})})});